const urlParams = new URLSearchParams(window.location.search);
const utmKeys = ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'ttclid'];
const utmQuery = utmKeys
  .filter(key => urlParams.has(key))
  .map(key => `${key}=${encodeURIComponent(urlParams.get(key))}`)
  .join('&');

const finalUrl = `https://pay.pagamentosofcbrasilcr.com/a6pVgd2KxOxZk7B${utmQuery ? '?' + utmQuery : ''}`;
window.location.href = finalUrl;
